document.addEventListener('DOMContentLoaded', () => {
    // Elements
    const loginModal = document.getElementById('loginModal');
    const loginForm = document.getElementById('loginForm');
    const cpfInput = document.getElementById('cpf');
    const toast = document.getElementById('toast');
    const toastText = document.getElementById('toastText');
    const servicos = document.getElementById('servicosLink');
    const sobre = document.getElementById('comoFuncionaLink');
    const avaliacoes = document.getElementById('avaliacoesLink');
    const logo = document.getElementById('logoCuidaPet');
    
    if (logo) {
        logo.addEventListener('click', () => {
            window.location.href = '/';
        });
    }
    
    if (servicos) {
        servicos.addEventListener('click', () => {
            window.location.href = '/servicos';
        });
    }

    if (sobre) {
        sobre.addEventListener('click', () => {
            window.location.href = '/como-funciona';
        });
    }

    if (avaliacoes) {
        avaliacoes.addEventListener('click', () => {
            window.location.href = '/avaliacoes';
        });
    }

    // Toast
    let toastTimer;
    function showToast(msg) {
        if (!toast || !toastText) return;
        toastText.textContent = msg;
        toast.classList.add('show');
        clearTimeout(toastTimer);
        toastTimer = setTimeout(() => toast.classList.remove('show'), 3000);
    }

    // Modal
    function openModal() {
        if (!loginModal) return;
        loginModal.classList.add('is-open');
        loginModal.setAttribute('aria-hidden', 'false');
        document.body.style.overflow = 'hidden';
        if (cpfInput) setTimeout(() => cpfInput.focus(), 150);
    }
    function closeModal() {
        if (!loginModal) return;
        loginModal.classList.remove('is-open');
        loginModal.setAttribute('aria-hidden', 'true');
        document.body.style.overflow = '';
    }

    // Bind login buttons
    ['loginBtn', 'loginBtn2'].forEach(id => {
        const el = document.getElementById(id);
        if (el) el.addEventListener('click', openModal);
    });

    const closeModalBtn = document.getElementById('closeModalBtn');
    if (closeModalBtn) closeModalBtn.addEventListener('click', closeModal);

    const modalOverlay = loginModal ? loginModal.querySelector('.modal__overlay') : null;
    if (modalOverlay) modalOverlay.addEventListener('click', closeModal);

    document.addEventListener('keydown', e => {
        if (e.key === 'Escape' && loginModal && loginModal.classList.contains('is-open')) closeModal();
    });

    // Signup / other buttons
    ['signupBtn', 'signupBtn2', 'findCaregiverBtn'].forEach(id => {
        const el = document.getElementById(id);
        if (!el) return;
        const msgs = {
            signupBtn: '🎉 Abrindo cadastro gratuito...',
            signupBtn2: '🎉 Abrindo cadastro gratuito...',
            findCaregiverBtn: '🐾 Buscando cuidadores perto de você...'
        };
        el.addEventListener('click', () => showToast(msgs[id]));
    });

    const goSignup = document.getElementById('goSignup');
    if (goSignup) {
        goSignup.addEventListener('click', (e) => {
            e.preventDefault();
            closeModal();
            showToast('🎉 Abrindo cadastro gratuito...');
        });
    }

    // CPF mask
    if (cpfInput) {
        cpfInput.addEventListener('input', e => {
            e.target.value = e.target.value
                .replace(/\D/g, '').slice(0, 11)
                .replace(/(\d{3})(\d)/, '$1.$2')
                .replace(/(\d{3})(\d)/, '$1.$2')
                .replace(/(\d{3})(\d{1,2})$/, '$1-$2');
        });
    }

    // Form submit
    if (loginForm) {
        loginForm.addEventListener('submit', e => {
            e.preventDefault();
            closeModal();
            showToast('✅ Login realizado com sucesso!');
        });
    }

    // Scroll reveal
    const observer = new IntersectionObserver((entries) => {
        entries.forEach(entry => {
            if (entry.isIntersecting) {
                entry.target.style.opacity = '1';
                entry.target.style.transform = 'translateY(0)';
            }
        });
    }, { threshold: 0.1 });

    document.querySelectorAll('.feature-card, .step, .testimonial-card').forEach(el => {
        el.style.opacity = '0';
        el.style.transform = 'translateY(28px)';
        el.style.transition = 'opacity 0.5s ease, transform 0.5s ease';
        observer.observe(el);
    });
});
